Köçürmə konstruktoru bir sinifin resurslarını başqa bir obyektə köçürən xüsusi konstruktor növüdür. Sintaksis:
class ClassName {
public:
  ClassName(ClassName&& other) noexcept;
};
Burada `noexcept` performansı artırır, çünki köçürmə əməliyyatının istisnasız olduğunu bildirir.

content.code:
#include <iostream>
#include <string>

class Resource {
public:
  std::string data;
  Resource(const std::string& d) : data(d) { std::cout << "Constructor\n"; }
  Resource(Resource&& other) noexcept : data(std::move(other.data)) {
    std::cout << "Move constructor\n";
    other.data = "";
  }
};

int main() {
  Resource obj1("Test");
  Resource obj2 = std::move(obj1);
  std::cout << "obj1: " << obj1.data << "\nobj2: " << obj2.data << std::endl;
  return 0;
}
// Output:
// Constructor
// Move constructor
// obj1: 
// obj2: Test

